// 1. Access the keywords array from the body of the webhook
const keywords = $json.body.keywords;

// 2. Check if the keywords field exists and is actually an array
if (Array.isArray(keywords)) {
  // 3. Map each string in the array to an n8n-compatible object
  return keywords.map(item => {
    return {
      json: {
        keyword: item,
        // Optional: include metadata from the body if needed
        city: $json.body.city,
        country: $json.body.country,
        placeId: $json.body.placeId
      }
    };
  });
}

// 4. Return an empty array if no keywords are found to prevent the workflow from crashing
return [];

// 1. Target the specific 'country' string inside the body
const body = $('Webhook').first().json.body || {};
const countryName = (body.country || "").toLowerCase().trim();

const countryMap = {
  "india": "in",
  "united states": "us",
  "usa": "us",
  "united kingdom": "gb",
  "uk": "gb",
  "canada": "ca",
  "australia": "au",
  "germany": "de",
  "france": "fr",
  "spain": "es",
  "italy": "it",
  "netherlands": "nl",
  "singapore": "sg",
  "uae": "ae",
  "united arab emirates": "ae",
  "saudi arabia": "sa",
  "south africa": "za",
  "bangladesh": "bd",
  "pakistan": "pk",
  "sri lanka": "lk",
  "nepal": "np",
  "malaysia": "my",
  "indonesia": "id",
  "philippines": "ph",
  "japan": "jp",
  "china": "cn"
};

// 2. Perform the lookup
const countryCode = countryMap[countryName] || "unknown";

return [
  {
    json: {
      Country: countryName || "not provided",
      CountryCode: countryCode,
      // Optional: keep the original data for the next steps
      originalData: body 
    }
  }
];

const results = [];

// 1. Get the payload from the Webhook
const payload = $('Webhook').first().json.body || $('Webhook').first().json;

// 2. Fix: Check for 'placeId' (as seen in your webhook) OR 'gmb place id'
const formPlaceId = (payload.placeId || payload['gmb place id'])?.toString().trim();

// If we still can't find a Place ID to search for
if (!formPlaceId) {
  return [
    {
      json: {
        status: "not_found",
        reason: "place_id_missing",
        debug_payload: payload // This helps you see what the node actually received
      }
    }
  ];
}

let isFound = false;

// 3. Loop through Apify scraped businesses
for (const item of $input.all()) {
  const data = item.json;
  const apiPlaceId = data.placeId;

  if (!apiPlaceId) continue;

  // Compare the ID from the form with the ID from the search results
  if (apiPlaceId.toString().trim() === formPlaceId) {
    isFound = true;
    results.push({
      status: "found",
      keyword: data.searchString,
      ranking_position: data.rank,
      business_name: data.title,
      category: data.categoryName,
      phone: data.phoneUnformatted || data.phone || null,
      website: data.website || null,
      rating: data.totalScore || null,
      reviews: data.reviewsCount || null,
      city: data.city,
      address: data.address,
      place_id: apiPlaceId,
      maps_url: data.url
    });
  }
}

// 4. If no match was found in the list
if (!isFound) {
  return [
    {
      json: {
        status: "not_found",
        place_id: formPlaceId,
        // Using optional chaining to prevent errors if the loop node name differs
        keyword: $('Loop Over Keywords').item?.json?.keyword || "Unknown", 
        ranking_position: "Not in Top Results"
      }
    }
  ];
}

// 5. Return found business(es)
return results.map(r => ({ json: r }));

// Get all items outputted by 'Find Matches' across all loop iterations
const allMatches = $('Find Matches').all();

const placeId = $('Webhook').first().json.body['gmb place id'] || $('Webhook').first().json['gmb place id'];
let businessDetails = null;
const keywordRankings = [];

for (const item of allMatches) {
    const data = item.json;

    // Grab the business details from the first successful match we find
    if (data.status === 'found' && !businessDetails) {
        businessDetails = {
            business_name: data.business_name,
            category: data.category,
            rating: data.rating,
            reviews: data.reviews,
            phone: data.phone,
            address: data.address,
            maps_url: data.maps_url
        };
    }

    // Add the keyword and its rank to our array
    keywordRankings.push({
        keyword: data.keyword,
        rank: data.ranking_position
    });
}

// Output the single, merged master record
return [{
    json: {
        place_id: placeId,
        business_name: businessDetails ? businessDetails.business_name : "Unknown",
        business_info: businessDetails || "Not found in top results",
        rankings: keywordRankings // This contains your array of { keyword, rank }
    }
}];
